const grpc = require('@grpc/grpc-js');
const protoLoader = require('@grpc/proto-loader');
const express = require('express');

class GrpcHeaderForwardingClient {
  constructor(protoPath, serviceName, grpcServerAddress) {
    const packageDefinition = protoLoader.loadSync(protoPath, {
      keepCase: true,
      longs: String,
      enums: String,
      defaults: true,
      oneofs: true
    });
    
    const protoDescriptor = grpc.loadPackageDefinition(packageDefinition);
    this.client = new protoDescriptor[serviceName](
      grpcServerAddress,
      grpc.credentials.createInsecure()
    );
  }

  createMetadataFromHeaders(headers, forwardedHeaders = []) {
    const metadata = new grpc.Metadata();
    
    const defaultForwardHeaders = [
      'user-agent',
      'x-forwarded-for',
      'x-forwarded-host',
      'x-forwarded-proto',
      'x-real-ip',
      'authorization',
      'x-request-id',
      'x-correlation-id',
      'accept',
      'accept-language',
      'content-type'
    ];

    const headersToForward = [...defaultForwardHeaders, ...forwardedHeaders];
    
    Object.keys(headers).forEach(key => {
      const lowerKey = key.toLowerCase();
      
      if (headersToForward.includes(lowerKey) || lowerKey.startsWith('x-')) {
        const value = headers[key];
        if (Array.isArray(value)) {
          value.forEach(v => metadata.add(lowerKey, v));
        } else {
          metadata.add(lowerKey, value);
        }
      }
    });

    return metadata;
  }

  call(method, request, headers, callback) {
    const metadata = this.createMetadataFromHeaders(headers);
    
    if (typeof this.client[method] !== 'function') {
      return callback(new Error(`Method ${method} not found on gRPC client`));
    }

    this.client[method](request, metadata, (error, response) => {
      if (error) {
        return callback(error);
      }
      callback(null, response);
    });
  }

  callWithPromise(method, request, headers) {
    return new Promise((resolve, reject) => {
      this.call(method, request, headers, (error, response) => {
        if (error) {
          reject(error);
        } else {
          resolve(response);
        }
      });
    });
  }

  streamingCall(method, request, headers) {
    const metadata = this.createMetadataFromHeaders(headers);
    
    if (typeof this.client[method] !== 'function') {
      throw new Error(`Method ${method} not found on gRPC client`);
    }

    return this.client[method](request, metadata);
  }
}

class GrpcGateway {
  constructor() {
    this.clients = new Map();
    this.app = express();
    this.app.use(express.json());
  }

  registerService(serviceName, protoPath, grpcServerAddress, customForwardHeaders = []) {
    const client = new GrpcHeaderForwardingClient(protoPath, serviceName, grpcServerAddress);
    this.clients.set(serviceName, {
      client,
      customForwardHeaders
    });
  }

  setupRoutes() {
    this.app.post('/grpc/:service/:method', async (req, res) => {
      const { service, method } = req.params;
      const request = req.body;
      const headers = req.headers;

      const serviceConfig = this.clients.get(service);
      
      if (!serviceConfig) {
        return res.status(404).json({ error: `Service ${service} not found` });
      }

      try {
        const response = await serviceConfig.client.callWithPromise(
          method,
          request,
          headers
        );
        res.json(response);
      } catch (error) {
        res.status(500).json({
          error: error.message,
          code: error.code,
          details: error.details
        });
      }
    });

    this.app.get('/health', (req, res) => {
      res.json({ status: 'healthy', services: Array.from(this.clients.keys()) });
    });
  }

  start(port = 3000) {
    this.setupRoutes();
    this.app.listen(port, () => {
      console.log(`gRPC Gateway listening on port ${port}`);
    });
  }
}

